import { cva } from "class-variance-authority";
import type { VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

import { Tooltip } from "./tooltip";

const githubStarsVariants = cva("gap-1.5 pr-1.5 pl-2", {
  defaultVariants: {
    size: "default",
  },
  variants: {
    size: {
      default: "h-9 text-sm",
      lg: "h-10 text-base pr-2 pl-2.5",
      sm: "h-8 text-xs",
    },
  },
});

interface GitHubStarsProps extends VariantProps<typeof githubStarsVariants> {
  repo: string;
  className?: string;
  locales?: Intl.LocalesArgument;
}

const getStarsCount = async (repo: string): Promise<number> => {
  try {
    const res = await fetch(`https://api.github.com/repos/${repo}`, {
      next: { revalidate: 60 * 60 * 24 },
    });

    if (!res.ok) {
      return 0;
    }

    const data = (await res.json()) as { stargazers_count: number };
    return Number(data.stargazers_count);
  } catch {
    return 0;
  }
};

export const GitHubStars = async ({
  repo,
  locales = "en-US",
  className,
  size,
}: GitHubStarsProps) => {
  const count = await getStarsCount(repo);

  const formatted = new Intl.NumberFormat(locales, {
    compactDisplay: "short",
    notation: "compact",
  })
    .format(count)
    .toLowerCase();

  const full = new Intl.NumberFormat(locales).format(count);

  return (
    <Tooltip content={`${full} stars`}>
      <button className={cn(githubStarsVariants({ size }), className)}>
        <a
          href={`https://github.com/${repo}`}
          target="_blank"
          rel="noopener noreferrer"
        >
          <svg
            className="-translate-y-px"
            viewBox="0 0 24 24"
            width="16"
            height="16"
            aria-hidden="true"
